```
#include <iostream>

int main() {
    int редови;
    std::cout << "Внесете број на редови: ";
    std::cin >> редови;
    за (int i = 1; i <= редови; i++) {
        за (int j = 1; j <= i; j++) {
            std::cout << "* ";
        }
        std::cout << std::endl;
    }
